const enforceStatBound = (
  ctx: z.RefinementCtx,
  path: string[],
  value: number,
  range: { readonly min: number; readonly max: number },
): void => {
  if (value < range.min) {
    ctx.addIssue({
      code: "custom",
      path,
      message: `must be at least ${range.min}`,
    });
  }

  if (value > range.max) {
    ctx.addIssue({
      code: "custom",
      path,
      message: `must be at most ${range.max}`,
    });
  }
};

